const translations={"staff_page_title":{tr:"Eğitim & Yönetim Kadromuz | Sapmaz Academy",en:"Our Staff & Flight Instructors | Sapmaz Academy"},"nav_about":{tr:"Hakkımızda",en:"About Us"},"nav_staff":{tr:"Kadromuz",en:"Our Staff"},"nav_courses":{tr:"Eğitimler",en:"Courses"},"nav_resources":{tr:"Kaynaklar",en:"Resources"},"nav_news":{tr:"Haberler",en:"News"},"nav_contact":{tr:"İletişim",en:"Contact"},"bc_home":{tr:"Ana Sayfa",en:"Home"},"staff_main_title":{tr:"Eğitim & Yönetim Kadromuz",en:"Our Staff & Flight Instructors"},"staff_main_subtitle":{tr:"Havacılık sektöründe uzun yıllar deneyim kazanmış, uzman eğitmen ve yönetici kadromuz ile tanışın.",en:"Meet our specialist flight instructors and executive administrative board with decades of combined aviation experience."},"tab_educators":{tr:"Eğitmenler",en:"Instructors"},"tab_administrators":{tr:"Yöneticiler",en:"Executives"},"staff_lbl_email":{tr:"E-Posta:",en:"Email:"},"staff_lbl_phone":{tr:"Telefon:",en:"Phone:"},"pagination_prev":{tr:"Önceki",en:"Previous"},"pagination_next":{tr:"Sonraki",en:"Next"},"no_staff_results":{tr:"Bu kategoride kayıtlı personel bulunamadı.",en:"No staff members found in this category."},"footer_title_about":{tr:"Sapmaz Havacılık",en:"Sapmaz Aviation"},"footer_desc":{tr:"Havacılık sektörüne yön veren Sapmaz Grubu, pilotluk ve drone teknolojilerindeki 20 yılı aşkın tecrübesiyle profesyoneller yetiştirir.",en:"Leading the aviation industry, Sapmaz Group trains professionals with over 20 years of experience in flight training & drone technology."},"footer_title_links":{tr:"Kurumsal Bilgiler",en:"Information Hub"},"footer_link_accreditations":{tr:"Sertifikalar ve Yetkilerimiz",en:"Accreditations & Certificates"},"footer_link_careers":{tr:"Havacılık Kariyer Rehberi",en:"Aviation Careers Guide"},"footer_link_privacy":{tr:"Gizlilik ve KVKK Politikası",en:"Privacy & GDPR Data Policy"},"footer_link_terms":{tr:"Kullanım Şartları",en:"Terms & Conditions"},"footer_title_contact":{tr:"İletişim Bilgileri",en:"Contact Information"},"contact_address_label":{tr:"Merkez Ofis",en:"Headquarters"},"contact_address":{tr:"Sapmaz Plaza, Kat: 4, Havacılık Cd. No:12, Kadıköy / İstanbul",en:"Sapmaz Plaza, Floor: 4, Havacilik St. No:12, Kadikoy / Istanbul"},"contact_email_label":{tr:"E-Posta",en:"Email Address"},"contact_phone_label":{tr:"Müşteri İlişkileri",en:"Customer Relations"},"footer_rights":{tr:"Tüm Hakları Saklıdır.",en:"All Rights Reserved."},"footer_design":{tr:"Havacılık Eğitim Sistemleri Tasarımı",en:"Aviation Training Systems Design"}};const staffData=[{id:1,name:"Yüzb. Ahmet Yılmaz",category:"educator",roleTR:"Hususi Pilotaj (PPL) Baş Uçuş Öğretmeni",roleEN:"Private Pilot License (PPL) Chief Flight Instructor",email:"ahmet.yilmaz@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 101)",imgUrl:"https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=300&auto=format&fit=crop"},{id:2,name:"Dr. Selin Kaya",category:"educator",roleTR:"İHA-2 Otonom Uçuş Sistemleri Uzman Eğitmeni",roleEN:"UAV-2 Autonomous Flight Systems Lead Instructor",email:"selin.kaya@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 102)",imgUrl:"https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=300&auto=format&fit=crop"},{id:3,name:"Kapt. Can Demir",category:"educator",roleTR:"Aletli Uçuş (IR) ve Çok Motor (ME) Uçuş Eğitmeni",roleEN:"Instrument Rating (IR) & Multi-Engine (ME) Flight Instructor",email:"can.demir@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 103)",imgUrl:"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=300&auto=format&fit=crop"},{id:4,name:"Murat Aksoy",category:"educator",roleTR:"İHA-0 / İHA-1 Temel Havacılık ve İHA Pilotaj Eğitmeni",roleEN:"UAV-0 / UAV-1 Basic Aviation & UAV Pilotage Instructor",email:"murat.aksoy@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 104)",imgUrl:"https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?q=80&w=300&auto=format&fit=crop"},{id:5,name:"Elif Şahin",category:"educator",roleTR:"Tarımsal İHA Uygulamaları ve Zirai Drone Eğitmeni",roleEN:"Agricultural UAV Operations Specialist Instructor",email:"elif.sahin@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 105)",imgUrl:"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?q=80&w=300&auto=format&fit=crop"},{id:6,name:"Kemal Sapmaz",category:"administrator",roleTR:"Sapmaz Havacılık Kurucusu & Yönetim Kurulu Başkanı",roleEN:"Sapmaz Aviation Founder & Chairman of the Board",email:"kemal@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 201)",imgUrl:"https://images.unsplash.com/photo-1560250097-0b93528c311a?q=80&w=300&auto=format&fit=crop"},{id:7,name:"Zeynep Yurt",category:"administrator",roleTR:"Akademi Direktörü & Eğitim Planlama Koordinatörü",roleEN:"Academy Director & Flight Training Coordinator",email:"zeynep.yurt@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 202)",imgUrl:"https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?q=80&w=300&auto=format&fit=crop"},{id:8,name:"Kapt. Serdar Kurt",category:"administrator",roleTR:"Baş Uçuş Öğretmeni (CFI) & Eğitim Kalite Müdürü",roleEN:"Chief Flight Instructor (CFI) & Quality Manager",email:"serdar.kurt@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 203)",imgUrl:"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=300&auto=format&fit=crop"},{id:9,name:"Burak Çelik",category:"administrator",roleTR:"İdari ve Mali İşler Koordinatörü",roleEN:"Administrative & Financial Operations Director",email:"burak.celik@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 204)",imgUrl:"https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=300&auto=format&fit=crop"},{id:10,name:"Ayşe Aydın",category:"administrator",roleTR:"Öğrenci İşleri ve Akademik Kayıt Sorumlusu",roleEN:"Student Affairs & Academic Registrar Coordinator",email:"ayse.aydin@sapmazacademy.com",phone:"+90 (216) 555 4282 (Dahili: 205)",imgUrl:"https://images.unsplash.com/photo-1580489944761-15a19d654956?q=80&w=300&auto=format&fit=crop"}];document.addEventListener("DOMContentLoaded",()=>{setupMobileMenu();setupTheme();setupLanguage();renderStaff()});function setupMobileMenu(){const hamburger=document.getElementById("hamburger");const navMenu=document.getElementById("navMenu");const navLinks=document.querySelectorAll(".nav-link");if(hamburger&&navMenu){hamburger.addEventListener("click",()=>{hamburger.classList.toggle("open");navMenu.classList.toggle("open")});navLinks.forEach(link=>{link.addEventListener("click",()=>{hamburger.classList.remove("open");navMenu.classList.remove("open")})})}}function setupTheme(){const themeToggleBtn=document.getElementById("themeToggle");const currentTheme=localStorage.getItem("theme");if(currentTheme==="light"){document.body.classList.add("light-mode")}if(themeToggleBtn){themeToggleBtn.addEventListener("click",()=>{document.body.classList.toggle("light-mode");const theme=document.body.classList.contains("light-mode")?"light":"dark";localStorage.setItem("theme",theme)})}}function setupLanguage(){const langSelect=document.getElementById("langSelect");let currentLang=localStorage.getItem("language")||"tr";if(langSelect){langSelect.value=currentLang;langSelect.addEventListener("change",(e)=>{const selectedLang=e.target.value;localStorage.setItem("language",selectedLang);updatePageLanguage(selectedLang);document.documentElement.lang=selectedLang;renderStaff()})}updatePageLanguage(currentLang)}function updatePageLanguage(lang){const translatableElements=document.querySelectorAll("[data-i18n]");translatableElements.forEach(element=>{const key=element.getAttribute("data-i18n");if(translations[key]&&translations[key][lang]){element.textContent=translations[key][lang]}})}function renderStaff(){const gridContainer=document.getElementById("staffGrid");const paginationContainer=document.getElementById("staffPagination");if(!gridContainer)return;const lang=localStorage.getItem("language")||"tr";const educators=staffData.filter(item=>item.category==="educator");const administrators=staffData.filter(item=>item.category==="administrator");if(staffData.length===0){const noResultsText=translations["no_staff_results"][lang];gridContainer.innerHTML=`<div class="news-no-results">${noResultsText}</div>`;return}let htmlContent="";if(educators.length>0){const educatorsTitle=translations["tab_educators"][lang];htmlContent+=`<h2 class="staff-category-title">${educatorsTitle}</h2><div class="staff-grid">`;educators.forEach(item=>{const role=lang==="tr"?item.roleTR:item.roleEN;htmlContent+=`<div class="staff-card"><div class="staff-card-img-wrapper"><img src="${item.imgUrl}" alt="${item.name}" class="staff-card-img" /></div><div class="staff-card-info"><h3 class="staff-card-name">${item.name}</h3><span class="staff-card-role">${role}</span></div></div>`});htmlContent+=`</div>`}if(administrators.length>0){const administratorsTitle=translations["tab_administrators"][lang];htmlContent+=`<h2 class="staff-category-title">${administratorsTitle}</h2><div class="staff-grid">`;administrators.forEach(item=>{const role=lang==="tr"?item.roleTR:item.roleEN;htmlContent+=`<div class="staff-card"><div class="staff-card-img-wrapper"><img src="${item.imgUrl}" alt="${item.name}" class="staff-card-img" /></div><div class="staff-card-info"><h3 class="staff-card-name">${item.name}</h3><span class="staff-card-role">${role}</span></div></div>`});htmlContent+=`</div>`}gridContainer.innerHTML=htmlContent;if(paginationContainer){paginationContainer.innerHTML=""}}